def norm(s): 
    return normalize_ar(s)

def lcs_length(a, b):
    # dynamic programming; can be large; but strings not huge
    # to be efficient, we can compute using difflib SequenceMatcher ratio; 
    # implement LCS for normalized tokens maybe. Let's use SequenceMatcher ratio anchored for LCS? We'll compute token-level Jaccard F1 later.
    sm = difflib.SequenceMatcher(a=a, b=b)
    return sum(tr.size for tr in sm.get_matching_blocks())

def similarity(a, b):
    na, nb = norm(a), norm(b)
    l = lcs_length(na, nb)
    return l*2/(len(na)+len(nb))

