def lcs_len(a, b):
    sm = difflib.SequenceMatcher(a=a, b=b)
    return sum(tr.size for tr in sm.get_matching_blocks())

def lcs_norm_by_orig(orig_text, cand_text):
    a = normalize_ar(orig_text)
    b = normalize_ar(cand_text)
    l = lcs_len(a, b)
    return l/len(a)

